def _budget_arg(value):
    """Validate a budget argument: a finite, non-negative number."""
    try:
        amount = float(value)
    except ValueError:
        raise argparse.ArgumentTypeError(f"invalid budget: {value!r}")
    if not math.isfinite(amount):
        raise argparse.ArgumentTypeError("budget must be a finite number")
    if amount < 0:
        raise argparse.ArgumentTypeError("budget must not be negative")
